#include<bits/stdc++.h>
using namespace std;
constexpr long long mod=1e9+7;
long long a[500010];
long long n,m,s[500010],cnt[500010];
vector<pair<long long,long long>> mp[500010];
vector<long long> mp1[500010];
long long in[500010],f[500010][2];
stack<long long> stk;
long long ans;
bool instk[500010];
long long dfn[500010],low[500010],edcccnt,edcc[500010],siz[500010],val[500010],dfncnt;
void tarjan(long long x,long long fa)
{
    dfn[x]=low[x]=++dfncnt;
    instk[x]=true;
    stk.push(x);
    for(auto i:mp[x])
    {
        long long v=i.first,id=i.second;
        if(id==(fa^1))
        {
            continue;
        }
        if(!dfn[v])
        {
            tarjan(v,id);
            low[x]=min(low[x],low[v]);
        }
        else if(instk[v])
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(low[x]==dfn[x])
    {
        edcccnt++;
        long long top;
        do
        {
            top=stk.top();
            stk.pop();
            edcc[top]=edcccnt;
            siz[edcccnt]++;
            instk[top]=false;
        }while(top!=x);
    }
}
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=1ll*ans*x%mod;
        }
        x=1ll*x*x%mod;
        y>>=1;
    }
    return ans;
}
void dfs(long long x,long long fa=-1)
{
    s[x]=cnt[x];
    for(long long i:mp1[x])
    {
        if(i!=fa)
        {
            dfs(i,x);
            s[x]+=s[i]+1;
        }
    }
}
void dp(long long x,long long fa=-1)
{
    for(long long i:mp1[x])
    {
        if(i!=fa)
        {
            dp(i,x);
            f[x][1]=(1ll*f[x][0]*f[i][1]%mod+1ll*f[x][1]*((1ll*f[i][0]*2%mod+f[i][1])%mod)%mod)%mod;
            f[x][0]=1ll*f[x][0]*(1ll*f[i][0]*2%mod)%mod;
        }
    }
    if(x==1)
    {
        ans=(ans+f[x][1])%mod;
    }
    else
    {
        ans=(ans+1ll*f[x][1]*fastpow(2,s[1]-s[x]-1)%mod)%mod;
    }
}
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=m;i++)
    {
        long long u,v;
        scanf("%lld%lld",&u,&v);
        mp[u].push_back(make_pair(v,i*2));
        mp[v].push_back(make_pair(u,i*2+1));
    }
    tarjan(1,-1);
    for(long long i=1;i<=n;i++)
    {
        for(auto k:mp[i])
        {
            long long j=k.first;
            if(edcc[i]!=edcc[j])
            {
                mp1[edcc[i]].push_back(edcc[j]);
            }
            else
            {
                cnt[edcc[i]]++;
            }
        }
    }
    for(long long i=1;i<=edcccnt;i++)
    {
        cnt[i]/=2;
        f[i][0]=fastpow(2,cnt[i]);
        f[i][1]=((fastpow(2,cnt[i]+siz[i])-f[i][0])%mod+mod)%mod;
    }
    dfs(1);
    dp(1);
    printf("%lld",(ans%mod+mod)%mod);
    return 0;
}
